"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[56239],{4697(i){i.exports=JSON.parse('{"tag":{"label":"tools","permalink":"/tags/tools","allTagsPath":"/tags","count":19,"items":[{"id":"entities/alby","title":"Alby","description":"Browser extension for Bitcoin Lightning payments and Nostr signing. Provides a non-custodial wallet with seamless web integration via the WebLN standard.","permalink":"/entities/alby"},{"id":"entities/braiins-hashpower","title":"Braiins Hashpower","description":"On-demand SHA-256 hashrate marketplace launched by Braiins in January 2026 (public beta). Miners buy and sell hashrate through a live order book without long-term contracts or hardware ownership.","permalink":"/entities/braiins-hashpower"},{"id":"entities/hashrate-autopilot","title":"Braiins Hashrate Autopilot","description":"Official automation tool from Braiins for managing hashrate bids on the Braiins Hashpower marketplace. Rules-based engine that buys hashrate when price crosses thresholds and auto-rebalances between pools.","permalink":"/entities/hashrate-autopilot"},{"id":"entities/btcmap","title":"BTCMap","description":"Open-source project mapping Bitcoin-accepting merchants and locations worldwide. Community-driven data using OpenStreetMap as the base layer.","permalink":"/entities/btcmap"},{"id":"entities/caravan","title":"Caravan","description":"Open-source multisig coordinator by Unchained Capital. Web-based tool for building and managing multisig transactions without installing software.","permalink":"/entities/caravan"},{"id":"entities/hashguard","title":"HashGuard","description":"DIY Python auto-optimizer for the Braiins Hashpower marketplace. Monitors the order book, detects stalled bids, and automatically adjusts pricing to maintain hashrate flow while minimizing overpayment.","permalink":"/entities/hashguard"},{"id":"entities/joinmarket","title":"JoinMarket","description":"Decentralized CoinJoin marketplace. Uses a maker-taker model where liquidity providers (makers) earn fees for providing inputs to CoinJoin transactions, while privacy seekers (takers) pay for the service.","permalink":"/entities/joinmarket"},{"id":"entities/lnbits","title":"LNbits","description":"An open-source Lightning accounting system that sits on top of a Lightning node. Provides a web interface, wallet system, and extensions for building Lightning-powered applications.","permalink":"/entities/lnbits"},{"id":"concepts/nostr","title":"Nostr","description":"Introduction to the Nostr protocol for censorship-resistant social networking, including clients, relays, NIPs, and integration with Lightning via Zaps.","permalink":"/concepts/nostr"},{"id":"entities/nunchuk","title":"Nunchuk","description":"Mobile-first Bitcoin wallet focused on multisig and collaborative custody. Designed for shared vaults and inheritance planning.","permalink":"/entities/nunchuk"},{"id":"entities/nutstash","title":"Nutstash","description":"Web-based Cashu ecash wallet. Enables users to hold and transfer Chaumian ecash tokens backed by Lightning Network bitcoin.","permalink":"/entities/nutstash"},{"id":"concepts/payjoin","title":"PayJoin","description":"Explanation of PayJoin (BIP-78) interactive transactions for improved on-chain privacy, wallet support, and coordination with receiver collaboration.","permalink":"/concepts/payjoin"},{"id":"entities/polar","title":"Polar","description":"A one-click Lightning Network simulator for local development and testing. Runs inside Docker and lets developers spin up private networks with multiple node implementations without touching mainnet.","permalink":"/entities/polar"},{"id":"entities/ronindojo","title":"RoninDojo","description":"Privacy-focused Bitcoin node operating system. On-chain only, with integrations for Whirlpool (CoinJoin) and Bisq.","permalink":"/entities/ronindojo"},{"id":"entities/samourai-wallet","title":"Samourai Wallet","description":"Privacy-focused Bitcoin wallet for Android, built around on-chain transaction privacy. The project was the origin of several privacy tools later adopted across the ecosystem.","permalink":"/entities/samourai-wallet"},{"id":"entities/specter-desktop","title":"Specter Desktop","description":"Open-source DIY multisig coordinator for Bitcoin. Runs as a desktop application with optional hardware wallet integration.","permalink":"/entities/specter-desktop"},{"id":"entities/strike","title":"Strike","description":"Consumer-friendly Bitcoin and Lightning payment application. Allows users to buy, sell, and send bitcoin with a focus on simplicity and low fees.","permalink":"/entities/strike"},{"id":"entities/wasabi-wallet","title":"Wasabi Wallet","description":"Privacy-focused Bitcoin desktop wallet with built-in CoinJoin coordination by default. Uses the WabiSabi credential protocol for CoinJoin transactions.","permalink":"/entities/wasabi-wallet"},{"id":"queries/what-privacy-stack-should-i-use-for-mobile","title":"What Privacy Stack Should I Use for Mobile?","description":"Matched privacy stack recommendations for iOS and Android based on threat model \u2014 from casual user to high-risk scenarios, covering wallets, networking, and communication.","permalink":"/queries/what-privacy-stack-should-i-use-for-mobile"}],"unlisted":false}}')}}]);